import{_ as e,o as r,c as t,a7 as l}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"よくある質問（FAQ）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/guides/faq.md","filePath":"ja/guides/faq.md","lastUpdated":1775394001000}'),o={name:"ja/guides/faq.md"};function i(h,a,s,n,d,q){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="よくある質問-faq" tabindex="-1">よくある質問（FAQ） <a class="header-anchor" href="#よくある質問-faq" aria-label="Permalink to &quot;よくある質問（FAQ）&quot;">​</a></h1><p>忘却前夜（Morimens）に関するよくある質問と回答です。</p><h2 id="ゲーム全般" tabindex="-1">ゲーム全般 <a class="header-anchor" href="#ゲーム全般" aria-label="Permalink to &quot;ゲーム全般&quot;">​</a></h2><h3 id="q-忘却前夜はどんなゲームですか" tabindex="-1">Q: 忘却前夜はどんなゲームですか？ <a class="header-anchor" href="#q-忘却前夜はどんなゲームですか" aria-label="Permalink to &quot;Q: 忘却前夜はどんなゲームですか？&quot;">​</a></h3><p>A: クトゥルフ神話（ラヴクラフト神話）をテーマとした<strong>ローグライト×デッキ構築×ガチャ</strong>のモバイルゲームです。覚醒体と呼ばれるキャラクターを集め、カードバトルで戦います。</p><h3 id="q-対応プラットフォームは" tabindex="-1">Q: 対応プラットフォームは？ <a class="header-anchor" href="#q-対応プラットフォームは" aria-label="Permalink to &quot;Q: 対応プラットフォームは？&quot;">​</a></h3><p>A: iOS / Android / PC（公式エミュレータ対応）。 <span class="server-badge server-cn">CN</span> <span class="server-badge server-global">Global</span> <span class="server-badge server-jp">JP</span> <span class="server-badge server-tw">TW</span> の各サーバーが運営されています。</p><h3 id="q-無課金でも楽しめますか" tabindex="-1">Q: 無課金でも楽しめますか？ <a class="header-anchor" href="#q-無課金でも楽しめますか" aria-label="Permalink to &quot;Q: 無課金でも楽しめますか？&quot;">​</a></h3><p>A: はい。SSR確率3%・30連天井と良心的なガチャ設計で、無課金でも十分に楽しめます。SR覚醒体も啓霊を重ねればSSRに匹敵する性能になります。</p><h2 id="戦闘システム" tabindex="-1">戦闘システム <a class="header-anchor" href="#戦闘システム" aria-label="Permalink to &quot;戦闘システム&quot;">​</a></h2><h3 id="q-算力-arithmetica-とは" tabindex="-1">Q: 算力（Arithmetica）とは？ <a class="header-anchor" href="#q-算力-arithmetica-とは" aria-label="Permalink to &quot;Q: 算力（Arithmetica）とは？&quot;">​</a></h3><p>A: カード使用に必要なリソースです。毎ターン<strong>5算力</strong>が回復し、カードのコスト分消費します。超維界域のシナジーで追加回復が可能です。</p><h3 id="q-狂気-madness-ゲージとは" tabindex="-1">Q: 狂気（Madness）ゲージとは？ <a class="header-anchor" href="#q-狂気-madness-ゲージとは" aria-label="Permalink to &quot;Q: 狂気（Madness）ゲージとは？&quot;">​</a></h3><p>A: 戦闘中に蓄積するゲージです。<strong>100に到達</strong>すると魂覚醒カード（バースト）が使用可能になります。使用後はリセットされます。</p><h3 id="q-銀鍵-silver-key-とは" tabindex="-1">Q: 銀鍵（Silver Key）とは？ <a class="header-anchor" href="#q-銀鍵-silver-key-とは" aria-label="Permalink to &quot;Q: 銀鍵（Silver Key）とは？&quot;">​</a></h3><p>A: 戦闘中に蓄積する上級リソースです。最大値は<strong>1000</strong>で、鍵令の効果に関わります。中盤以降に解放されます。</p><h3 id="q-編成は何体まで" tabindex="-1">Q: 編成は何体まで？ <a class="header-anchor" href="#q-編成は何体まで" aria-label="Permalink to &quot;Q: 編成は何体まで？&quot;">​</a></h3><p>A: <strong>最大4体</strong>です。同一覚醒体の重複配置は不可です。</p><h2 id="召喚-ガチャ" tabindex="-1">召喚（ガチャ） <a class="header-anchor" href="#召喚-ガチャ" aria-label="Permalink to &quot;召喚（ガチャ）&quot;">​</a></h2><h3 id="q-ssrの排出率は" tabindex="-1">Q: SSRの排出率は？ <a class="header-anchor" href="#q-ssrの排出率は" aria-label="Permalink to &quot;Q: SSRの排出率は？&quot;">​</a></h3><p>A: **3%**です。</p><h3 id="q-天井は何連" tabindex="-1">Q: 天井は何連？ <a class="header-anchor" href="#q-天井は何連" aria-label="Permalink to &quot;Q: 天井は何連？&quot;">​</a></h3><p>A: <strong>30連</strong>です。天井到達時にピックアップSSRが確定入手できます。</p><h3 id="q-天井カウントはバナー間で引き継がれますか" tabindex="-1">Q: 天井カウントはバナー間で引き継がれますか？ <a class="header-anchor" href="#q-天井カウントはバナー間で引き継がれますか" aria-label="Permalink to &quot;Q: 天井カウントはバナー間で引き継がれますか？&quot;">​</a></h3><p>A: バナーごとに独立しています。引き継がれません。</p><h2 id="育成" tabindex="-1">育成 <a class="header-anchor" href="#育成" aria-label="Permalink to &quot;育成&quot;">​</a></h2><h3 id="q-カードは最大何レベルまで強化できますか" tabindex="-1">Q: カードは最大何レベルまで強化できますか？ <a class="header-anchor" href="#q-カードは最大何レベルまで強化できますか" aria-label="Permalink to &quot;Q: カードは最大何レベルまで強化できますか？&quot;">​</a></h3><p>A: <strong>Lv.6</strong>が最大です。Lv.6への強化には特殊素材が必要です。</p><h3 id="q-啓霊-凸-は最大何回" tabindex="-1">Q: 啓霊（凸）は最大何回？ <a class="header-anchor" href="#q-啓霊-凸-は最大何回" aria-label="Permalink to &quot;Q: 啓霊（凸）は最大何回？&quot;">​</a></h3><p>A: <strong>5凸</strong>（同一覚醒体6体分）が最大です。</p><h3 id="q-育成で最も優先すべきことは" tabindex="-1">Q: 育成で最も優先すべきことは？ <a class="header-anchor" href="#q-育成で最も優先すべきことは" aria-label="Permalink to &quot;Q: 育成で最も優先すべきことは？&quot;">​</a></h3><p>A: メインアタッカー1体の集中育成です。レベル上げ→指令カードLv.3強化→昇格の順で進めましょう。</p><h2 id="サーバー関連" tabindex="-1">サーバー関連 <a class="header-anchor" href="#サーバー関連" aria-label="Permalink to &quot;サーバー関連&quot;">​</a></h2><h3 id="q-jpサーバーと他サーバーの違いは" tabindex="-1">Q: JPサーバーと他サーバーの違いは？ <a class="header-anchor" href="#q-jpサーバーと他サーバーの違いは" aria-label="Permalink to &quot;Q: JPサーバーと他サーバーの違いは？&quot;">​</a></h3><p>A: バランス調整のタイミングやイベント実装順が異なります。CN版の攻略情報がそのまま適用できない場合があるため注意してください。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><span class="server-badge server-jp">JP</span> JPサーバー固有の調整については、本Wikiの各ページで注記しています。</p></div><h3 id="q-サーバー間のデータ移行はできますか" tabindex="-1">Q: サーバー間のデータ移行はできますか？ <a class="header-anchor" href="#q-サーバー間のデータ移行はできますか" aria-label="Permalink to &quot;Q: サーバー間のデータ移行はできますか？&quot;">​</a></h3><p>A: サーバー間のデータ移行には対応していません。</p><h2 id="その他" tabindex="-1">その他 <a class="header-anchor" href="#その他" aria-label="Permalink to &quot;その他&quot;">​</a></h2><h3 id="q-コラボイベントはありますか" tabindex="-1">Q: コラボイベントはありますか？ <a class="header-anchor" href="#q-コラボイベントはありますか" aria-label="Permalink to &quot;Q: コラボイベントはありますか？&quot;">​</a></h3><p>A: はい。「沙耶の唄」（ニトロプラス）とのコラボが実施されています。詳細は<a href="./../events/collab.html">コラボイベント</a>をご覧ください。</p><h3 id="q-リセマラは必要ですか" tabindex="-1">Q: リセマラは必要ですか？ <a class="header-anchor" href="#q-リセマラは必要ですか" aria-label="Permalink to &quot;Q: リセマラは必要ですか？&quot;">​</a></h3><p>A: 30連天井が良心的なため、必須ではありません。ただし、好きなSSR覚醒体でスタートしたい場合はリセマラを推奨します。</p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./beginner.html">初心者ガイド</a></li><li><a href="./../modes/gacha.html">召喚システム</a></li><li><a href="./../modes/combat.html">戦闘システム</a></li><li><a href="./../awakeners/leveling.html">育成ガイド</a></li></ul>',45)])])}const b=e(o,[["render",i]]);export{p as __pageData,b as default};
